-- Acts 13: The First Missionary Journey Begins; Paul''s Pisidian Antioch Sermon

-- 1. Chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 13,
  'Acts 13 launches the first missionary journey, the decisive turn from Jerusalem-and-Judea focus to the Gentile mission under Pauline leadership. The Antioch church, rich in prophets and teachers of diverse backgrounds (Barnabas, Simeon called Niger, Lucius of Cyrene, Manaen the foster-brother of Herod Antipas, and Saul), is fasting and ministering to the Lord when the Holy Spirit directly speaks: "Separate me Barnabas and Saul for the work whereunto I have called them." With laying-on of hands and prayer, the church releases them. They sail to Cyprus, traverse the island, and confront the Jewish sorcerer Bar-Jesus (Elymas) in the retinue of the proconsul Sergius Paulus at Paphos — the first recorded encounter between the apostle and the pagan power of the Roman Empire. Paul, filled with the Holy Spirit, pronounces temporary blindness on Elymas; Sergius Paulus believes "astonished at the doctrine of the Lord." Subtly, Luke notes Saul''s assumption of the Greek name Paul and shifts from "Barnabas and Saul" to "Paul and his company" — the apostle is now in foreground. Crossing to the Anatolian mainland, John Mark defects at Perga; the party presses north to Pisidian Antioch. In the synagogue on the sabbath, Paul delivers his first full recorded sermon: a Heilsgeschichte from the exodus through David, fastened onto Jesus as the promised Son of David, proclaiming his resurrection from Psalm 2, Isaiah 55, and Psalm 16, and announcing justification by faith apart from the law — the programmatic statement "by him all that believe are justified from all things, from which ye could not be justified by the law of Moses." The Gentiles beg to hear the same message the next sabbath, and nearly the whole city gathers. But the Jews, moved with envy, contradict and blaspheme; Paul and Barnabas formally turn to the Gentiles, citing Isaiah 49:6 — a second epoch-making declaration. Iconium beckons; the persecuted missionaries shake off the dust and advance, leaving behind disciples "filled with joy, and with the Holy Ghost."',
  'Justified by Faith: the Gentile Mission Launches from Antioch',
  'δικαιοῦται',
  'is justified, declared righteous',
  '["The Antioch church sends Barnabas and Saul (vv.1-3)", "Mission on Cyprus; the sorcerer Elymas blinded (vv.4-12)", "John Mark leaves; arrival at Pisidian Antioch (vv.13-15)", "Paul''s synagogue sermon: the gospel fulfilling Israel''s story (vv.16-41)", "Gentile interest, Jewish opposition, turn to the Gentiles (vv.42-52)"]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

-- 2. Verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Now there were in the church that was at Antioch certain prophets and teachers; as Barnabas, and Simeon that was called Niger, and Lucius of Cyrene, and Manaen, which had been brought up with Herod the tetrarch, and Saul.',
   'Ἦσαν δὲ ἐν Ἀντιοχείᾳ κατὰ τὴν οὖσαν ἐκκλησίαν προφῆται καὶ διδάσκαλοι, ὅ τε Βαρναβᾶς καὶ Συμεὼν ὁ καλούμενος Νίγερ, καὶ Λούκιος ὁ Κυρηναῖος, Μαναήν τε Ἡρῴδου τοῦ τετραάρχου σύντροφος καὶ Σαῦλος.',
   'Ēsan de en Antiocheia kata tēn ousan ekklēsian prophētai kai didaskaloi, ho te Barnabas kai Symeōn ho kaloumenos Niger, kai Loukios ho Kyrēnaios, Manaēn te Hērōdou tou tetraarchou syntrophos kai Saulos.',
   'The Antioch leadership is strikingly diverse: a Cypriot Levite (Barnabas), a North African Jew with a Latin nickname ("Niger" — black), another Cyrenian, a Jewish aristocrat raised in Herod''s court, and a Tarsian Pharisee. "Syntrophos" ("brought up with") indicates Manaen was Herod''s childhood foster-brother. Five men from four regions and multiple social strata model the multi-ethnic leadership of the church that first bore the name "Christian."',
   'The leadership of the gospel mission is intrinsically multi-ethnic and socially diverse. God gathers his servants from every quarter to reach every quarter; the team at Antioch prefigures the global church.'),
  (2, 'As they ministered to the Lord, and fasted, the Holy Ghost said, Separate me Barnabas and Saul for the work whereunto I have called them.',
   'λειτουργούντων δὲ αὐτῶν τῷ κυρίῳ καὶ νηστευόντων εἶπεν τὸ πνεῦμα τὸ ἅγιον· ἀφορίσατε δή μοι τὸν Βαρναβᾶν καὶ Σαῦλον εἰς τὸ ἔργον ὃ προσκέκλημαι αὐτούς.',
   'Leitourgountōn de autōn tō kyriō kai nēsteuontōn eipen to pneuma to hagion; aphorisate dē moi ton Barnaban kai Saulon eis to ergon ho proskeklēmai autous.',
   '"Leitourgountōn" ("ministering") is the word from which ''liturgy'' derives — it describes priestly service. Prophetic leaders engage in cultic worship coupled with fasting. The Spirit speaks personally: "me… I have called." The missionary charge originates in the Godhead, not in human strategy.',
   'The Holy Spirit is the personal initiator and executive of Christian mission. Apostles are released, not generated, by the church; the Spirit authors the call and the congregation confirms it.'),
  (3, 'And when they had fasted and prayed, and laid their hands on them, they sent them away.',
   'τότε νηστεύσαντες καὶ προσευξάμενοι καὶ ἐπιθέντες τὰς χεῖρας αὐτοῖς ἀπέλυσαν.',
   'Tote nēsteusantes kai proseuxamenoi kai epithentes tas cheiras autois apelysan.',
   'Laying on of hands conveys no new apostolic authority (Paul already had his) but is the communal act of identifying and commissioning. The Antioch church''s sacrifice — releasing two of its best — is the precondition of worldwide mission.',
   'Authentic missionary sending costs the local church its finest workers. No church is genuinely global until it willingly releases what it treasures most into the Spirit''s wider service.'),
  (4, 'So they, being sent forth by the Holy Ghost, departed unto Seleucia; and from thence they sailed to Cyprus.',
   'αὐτοὶ μὲν οὖν ἐκπεμφθέντες ὑπὸ τοῦ ἁγίου πνεύματος κατῆλθον εἰς Σελεύκειαν, ἐκεῖθέν τε ἀπέπλευσαν εἰς Κύπρον,',
   'Autoi men oun ekpemphthentes hypo tou hagiou pneumatos katēlthon eis Seleukeian, ekeithen te apepleusan eis Kypron,',
   'Luke specifies the true Sender: "by the Holy Ghost." Seleucia is Antioch''s Mediterranean port; Cyprus is Barnabas''s homeland (4:36), making it the natural first target. The island was strategically accessible (about 80 miles away) and had synagogues from the Ptolemaic period.',
   'Strategic wisdom and Spirit-direction harmonize in Christian mission. The first missionary journey begins where known relational networks and divine calling intersect; faith does not despise prudence.'),
  (5, 'And when they were at Salamis, they preached the word of God in the synagogues of the Jews: and they had also John to their minister.',
   'καὶ γενόμενοι ἐν Σαλαμῖνι κατήγγελλον τὸν λόγον τοῦ θεοῦ ἐν ταῖς συναγωγαῖς τῶν Ἰουδαίων· εἶχον δὲ καὶ Ἰωάννην ὑπηρέτην.',
   'Kai genomenoi en Salamini katēngellon ton logon tou theou en tais synagōgais tōn Ioudaiōn; eichon de kai Iōannēn hypēretēn.',
   'Salamis was Cyprus''s eastern port; multiple synagogues indicate a substantial Jewish population. "Hypēretēn" ("minister, assistant") was John Mark''s role — handling logistics, teaching new converts, preparing venues. The missionary pattern: synagogue first, Gentiles after.',
   'Apostolic strategy begins with existing people of the covenant. Paul''s pattern — synagogue first, city second — honors the priority of Israel while opening the door wide to the nations who frequent synagogue precincts.'),
  (6, 'And when they had gone through the isle unto Paphos, they found a certain sorcerer, a false prophet, a Jew, whose name was Barjesus:',
   'διελθόντες δὲ ὅλην τὴν νῆσον ἄχρι Πάφου εὗρον ἄνδρα τινὰ μάγον ψευδοπροφήτην Ἰουδαῖον ᾧ ὄνομα Βαριησοῦ,',
   'Dielthontes de holēn tēn nēson achri Paphou heuron andra tina magon pseudoprophētēn Ioudaion hō onoma Bariēsou,',
   'Paphos was Cyprus''s western capital and residence of the Roman proconsul. "Magon" and "pseudoprophētēn" pile on condemnation: Bar-Jesus is a sorcerer and false prophet, and a Jew — the last detail sharpens the scandal. His Aramaic name means "son of Jesus," probably unrelated to the Lord Jesus; Elymas (v.8) is likely a Semitic epithet meaning "magician."',
   'The greatest spiritual opposition to the gospel often comes from within the religious community itself. Satan''s most effective false prophets borrow the vocabulary and credentials of God''s people, making discernment indispensable.'),
  (7, 'Which was with the deputy of the country, Sergius Paulus, a prudent man; who called for Barnabas and Saul, and desired to hear the word of God.',
   'ὃς ἦν σὺν τῷ ἀνθυπάτῳ Σεργίῳ Παύλῳ, ἀνδρὶ συνετῷ. οὗτος προσκαλεσάμενος Βαρναβᾶν καὶ Σαῦλον ἐπεζήτησεν ἀκοῦσαι τὸν λόγον τοῦ θεοῦ·',
   'Hos ēn syn tō anthypatō Sergiō Paulō, andri synetō. Houtos proskalesamenos Barnaban kai Saulon epezētēsen akousai ton logon tou theou;',
   '"Anthypatos" ("proconsul") is precisely correct for Cyprus under senatorial administration from 22 BC — Luke''s political title usage is archeologically verifiable. "Sergius Paulus" is attested in inscriptions from Cyprus and Pisidian Antioch; several bear a family connection. "Synetos" ("prudent, intelligent") positions him favorably from the outset.',
   'God prepares thoughtful, seeking individuals within the pagan power structure. The Roman proconsul of Cyprus, a Gentile of intellectual substance, is the first recorded senior Roman official to hear the gospel — and to believe it.'),
  (8, 'But Elymas the sorcerer (for so is his name by interpretation) withstood them, seeking to turn away the deputy from the faith.',
   'ἀνθίστατο δὲ αὐτοῖς Ἐλύμας ὁ μάγος, οὕτως γὰρ μεθερμηνεύεται τὸ ὄνομα αὐτοῦ, ζητῶν διαστρέψαι τὸν ἀνθύπατον ἀπὸ τῆς πίστεως.',
   'Anthistato de autois Elymas ho magos, houtōs gar methermēneuetai to onoma autou, zētōn diastrepsai ton anthypaton apo tēs piseōs.',
   '"Anthistato" ("resisted") — the verb evokes the satanic resistance Paul later describes in 2 Tim 3:8 (Jannes and Jambres withstanding Moses). Satan tries to keep the seeker from faith by the influence-of-association with false religion.',
   'Spiritual warfare is especially fierce at the moment of conversion. The devil employs the nearest false teacher to obstruct genuine seekers from responding to the gospel; the enemy''s final weapon is often a spiritually-titled friend.'),
  (9, 'Then Saul, (who also is called Paul,) filled with the Holy Ghost, set his eyes on him.',
   'Σαῦλος δέ, ὁ καὶ Παῦλος, πλησθεὶς πνεύματος ἁγίου ἀτενίσας εἰς αὐτὸν',
   'Saulos de, ho kai Paulos, plēstheis pneumatos hagiou atenisas eis auton',
   'Luke''s first use of "Paulos" (Latin Paulus) — the Greek name had always been Saul''s Roman-citizen alternate; Luke switches now, perhaps because of the eponymous proconsul but more deeply because the apostle is entering his Gentile missionary identity. "Plēstheis pneumatos hagiou" signals prophetic empowerment for the confrontation.',
   'The Spirit empowers believers for decisive confrontations with spiritual darkness. Pentecostal fullness is not only for preaching but for the moments when satanic opposition must be directly addressed and dispelled.'),
  (10, 'And said, O full of all subtilty and all mischief, thou child of the devil, thou enemy of all righteousness, wilt thou not cease to pervert the right ways of the Lord?',
   'εἶπεν· ὦ πλήρης παντὸς δόλου καὶ πάσης ῥᾳδιουργίας, υἱὲ διαβόλου, ἐχθρὲ πάσης δικαιοσύνης, οὐ παύσῃ διαστρέφων τὰς ὁδοὺς τοῦ κυρίου τὰς εὐθείας;',
   'Eipen; ō plērēs pantos dolou kai pasēs rhadiourgias, huie diabolou, echthre pasēs dikaiosynēs, ou pausē diastrephōn tas hodous tou kyriou tas eutheias?',
   'Paul''s invective is surgical: "son of the devil" is a pointed pun on "son of Jesus" (Bar-Jesus). The description echoes Isaiah 40:3-4 ("straight paths") and John 8:44 (devil''s children).',
   'Compassion for the seeker sometimes requires severity to the seducer. Apostolic love for Sergius Paulus requires public exposure of Elymas; true love refuses to soften the rebuke that a soul''s destiny requires.'),
  (11, 'And now, behold, the hand of the Lord is upon thee, and thou shalt be blind, not seeing the sun for a season. And immediately there fell on him a mist and a darkness; and he went about seeking some to lead him by the hand.',
   'καὶ νῦν ἰδοὺ χεὶρ κυρίου ἐπὶ σέ, καὶ ἔσῃ τυφλὸς μὴ βλέπων τὸν ἥλιον ἄχρι καιροῦ. παραχρῆμα δὲ ἔπεσεν ἐπ’ αὐτὸν ἀχλὺς καὶ σκότος, καὶ περιάγων ἐζήτει χειραγωγούς.',
   'Kai nyn idou cheir kyriou epi se, kai esē typhlos mē blepōn ton hēlion achri kairou. Parachrēma de epesen ep'' auton achlys kai skotos, kai periagōn ezētei cheiragōgous.',
   'The blindness is "achri kairou" ("for a season") — chastening rather than destroying; room remains for repentance. The physical judgment mirrors the spiritual blindness that was already Elymas''s state. "Cheiragōgous" ("hand-leaders") echoes Paul''s own blindness after conversion (9:8) — deliberate parallel.',
   'God''s judgments are often redemptive chastisements aimed at repentance. The temporary nature of the punishment is itself grace; Elymas tastes the blindness that once led Saul to conversion.'),
  (12, 'Then the deputy, when he saw what was done, believed, being astonished at the doctrine of the Lord.',
   'τότε ἰδὼν ὁ ἀνθύπατος τὸ γεγονὸς ἐπίστευσεν ἐκπλησσόμενος ἐπὶ τῇ διδαχῇ τοῦ κυρίου.',
   'Tote idōn ho anthypatos to gegonos episteusen ekplēssomenos epi tē didachē tou kyriou.',
   'Luke''s careful phrasing is significant: the proconsul was astonished not at the miracle alone but "at the doctrine of the Lord" — the teaching which the sign authenticated. Sergius Paulus is the first recorded Roman proconsul to believe, a political harbinger.',
   'Genuine faith is produced by the teaching of the Lord, not merely by sign. Miracles open the door; doctrine furnishes the house; conversion is to a confessed truth about Christ, not a dazzled response to marvel.'),
  (13, 'Now when Paul and his company loosed from Paphos, they came to Perga in Pamphylia: and John departing from them returned to Jerusalem.',
   'Ἀναχθέντες δὲ ἀπὸ τῆς Πάφου οἱ περὶ Παῦλον ἦλθον εἰς Πέργην τῆς Παμφυλίας· Ἰωάννης δὲ ἀποχωρήσας ἀπ’ αὐτῶν ὑπέστρεψεν εἰς Ἱεροσόλυμα.',
   'Anachthentes de apo tēs Paphou hoi peri Paulon ēlthon eis Pergēn tēs Pamphylias; Iōannēs de apochōrēsas ap'' autōn hypestrepsen eis Hierosolyma.',
   '"Hoi peri Paulon" ("Paul''s company") marks a subtle shift: Paul, not Barnabas, is now the leader. John Mark''s defection at Perga becomes the basis for the later division between Paul and Barnabas (15:37-39). Luke does not speculate on causes; perhaps Mark balked at the Gentile focus, the coastal-to-highland ascent, or homesickness.',
   'Christian teams experience painful defections. The work of mission is taxing enough to expose immature disciples; the departure of John Mark is a providence that will wound, heal, and later restore (cf. 2 Tim 4:11).'),
  (14, 'But when they departed from Perga, they came to Antioch in Pisidia, and went into the synagogue on the sabbath day, and sat down.',
   'αὐτοὶ δὲ διελθόντες ἀπὸ τῆς Πέργης παρεγένοντο εἰς Ἀντιόχειαν τὴν Πισιδίαν, καὶ εἰσελθόντες εἰς τὴν συναγωγὴν τῇ ἡμέρᾳ τῶν σαββάτων ἐκάθισαν.',
   'Autoi de dielthontes apo tēs Pergēs paregenonto eis Antiocheian tēn Pisidian, kai eiselthontes eis tēn synagōgēn tē hēmera tōn sabbatōn ekathisan.',
   'Pisidian Antioch was a Roman colony, ~3,600 feet above sea level in Galatia. The journey from Perga through the Taurus Mountains was notoriously dangerous (Paul alludes to "perils of rivers" and "perils of robbers" in 2 Cor 11:26). The visit likely reflects an illness that drove Paul upland (Gal 4:13).',
   'Missionary providence turns obstacles into openings. The physical condition that drove Paul into the highlands becomes the occasion of the first sustained Gentile gospel proclamation in Asia Minor.'),
  (15, 'And after the reading of the law and the prophets the rulers of the synagogue sent unto them, saying, Ye men and brethren, if ye have any word of exhortation for the people, say on.',
   'μετὰ δὲ τὴν ἀνάγνωσιν τοῦ νόμου καὶ τῶν προφητῶν ἀπέστειλαν οἱ ἀρχισυνάγωγοι πρὸς αὐτοὺς λέγοντες· ἄνδρες ἀδελφοί, εἴ τις ἔστιν ἐν ὑμῖν λόγος παρακλήσεως πρὸς τὸν λαόν, λέγετε.',
   'Meta de tēn anagnōsin tou nomou kai tōn prophētōn apesteilan hoi archisynagōgoi pros autous legontes; andres adelphoi, ei tis estin en hymin logos paraklēseōs pros ton laon, legete.',
   'The synagogue liturgy (Torah and Haftarah readings, then invitation to an exhortation from a visiting rabbi) provides Paul''s first great opportunity. "Logos paraklēseōs" ("word of exhortation") is a standing technical phrase for synagogue homily (cf. Heb 13:22).',
   'God grants the gospel natural platforms in the existing religious architecture of the nations. Paul seizes the synagogue''s own inherited form to announce that its every line of Scripture finds its "yea and amen" in Christ.'),
  (16, 'Then Paul stood up, and beckoning with his hand said, Men of Israel, and ye that fear God, give audience.',
   'ἀναστὰς δὲ Παῦλος καὶ κατασείσας τῇ χειρὶ εἶπεν· ἄνδρες Ἰσραηλῖται καὶ οἱ φοβούμενοι τὸν θεόν, ἀκούσατε.',
   'Anastas de Paulos kai kataseisas tē cheiri eipen; andres Israēlitai kai hoi phoboumenoi ton theon, akousate.',
   'Paul addresses two groups: ethnic Israelites and God-fearing Gentiles. The dual address is programmatic — the sermon will consciously bind both into a single gospel proclamation.',
   'Gospel preaching addresses both covenant heirs and Gentile seekers with the same message. The one Messiah of Israel is the one Savior of the nations; Paul refuses to divide his audience theologically.'),
  (17, 'The God of this people of Israel chose our fathers, and exalted the people when they dwelt as strangers in the land of Egypt, and with an high arm brought he them out of it.',
   'ὁ θεὸς τοῦ λαοῦ τούτου Ἰσραὴλ ἐξελέξατο τοὺς πατέρας ἡμῶν καὶ τὸν λαὸν ὕψωσεν ἐν τῇ παροικίᾳ ἐν γῇ Αἰγύπτου, καὶ μετὰ βραχίονος ὑψηλοῦ ἐξήγαγεν αὐτοὺς ἐξ αὐτῆς,',
   'Ho theos tou laou toutou Israēl exelexato tous pateras hēmōn kai ton laon hypsōsen en tē paroikia en gē Aigyptou, kai meta brachionos hypsēlou exēgagen autous ex autēs,',
   '"Exelexato" ("chose") — divine election anchors the whole history. "Meta brachionos hypsēlou" ("with a high arm") is Septuagint language for the exodus deliverance (Exod 6:6; Deut 4:34). Paul begins with the story his audience knows best.',
   'Gospel preaching to Jewish hearers starts with the sovereign electing grace of God in their own story. The God of Christ is the God of Abraham, Isaac, Jacob, and the Exodus; the gospel does not replace but fulfills this history.'),
  (18, 'And about the time of forty years suffered he their manners in the wilderness.',
   'καὶ ὡς τεσσερακονταετῆ χρόνον ἐτροποφόρησεν αὐτοὺς ἐν τῇ ἐρήμῳ,',
   'Kai hōs tesserakontaetē chronon etropophorēsen autous en tē erēmō,',
   '"Etropophorēsen" ("he bore with their manners") is a striking verb of divine forbearance through Israel''s rebellions. Paul compresses forty years of sins into one word of grace.',
   'God''s long-suffering is the essential backdrop of redemptive history. The same patience that bore with Israel''s wilderness murmuring now bears with the Gentile nations — and bore with Saul the persecutor — so that mercy might reach a world of sinners.'),
  (19, 'And when he had destroyed seven nations in the land of Chanaan, he divided their land to them by lot.',
   'καθελὼν ἔθνη ἑπτὰ ἐν γῇ Χανάαν κατεκληρονόμησεν τὴν γῆν αὐτῶν',
   'Kathelōn ethnē hepta en gē Chanaan kateklēronomēsen tēn gēn autōn',
   'The seven Canaanite nations are listed in Deut 7:1. Paul telescopes Joshua and the conquest into a single clause — his aim is not historical detail but theological trajectory.',
   'Divine sovereignty governs the rise and fall of nations. The same God who dispossessed Canaan to plant Israel is about to dispossess the powers of darkness to plant his church; the conquest typifies the gospel''s advance.'),
  (20, 'And after that he gave unto them judges about the space of four hundred and fifty years, until Samuel the prophet.',
   'ὡς ἔτεσιν τετρακοσίοις καὶ πεντήκοντα. καὶ μετὰ ταῦτα ἔδωκεν κριτὰς ἕως Σαμουὴλ τοῦ προφήτου.',
   'Hōs etesin tetrakosiois kai pentēkonta. Kai meta tauta edōken kritas heōs Samouēl tou prophētou.',
   'The 450-year figure matches 400 years in Egypt, 40 in wilderness, and ~10 for conquest — though the textual variant has generated centuries of discussion. The judges span from Joshua''s death to Samuel''s emergence (c. 1380-1050 BC).',
   'God provides leadership suited to each epoch of his people''s life. Judges, prophets, and kings are all providentially ordered toward the ultimate David-Son, Christ the King.'),
  (21, 'And afterward they desired a king: and God gave unto them Saul the son of Cis, a man of the tribe of Benjamin, by the space of forty years.',
   'κἀκεῖθεν ᾐτήσαντο βασιλέα, καὶ ἔδωκεν αὐτοῖς ὁ θεὸς τὸν Σαοὺλ υἱὸν Κίς, ἄνδρα ἐκ φυλῆς Βενιαμίν, ἔτη τεσσεράκοντα·',
   'Kakeithen ētēsanto basilea, kai edōken autois ho theos ton Saoul huion Kis, andra ek phylēs Beniamin, etē tesserakonta;',
   'Paul mentions King Saul by name — his own tribal namesake. The 40-year reign is confirmed here and nowhere else explicitly (1 Sam is silent on the length). Paul-of-Benjamin is about to preach Jesus-of-Judah.',
   'God meets his people where they ask, even when their request is misdirected. Paul acknowledges Israel''s flawed demand for a king while tracing God''s ordering providence through the flaw to the ultimate king, David''s son.'),
  (22, 'And when he had removed him, he raised up unto them David to be their king; to whom also he gave testimony, and said, I have found David the son of Jesse, a man after mine own heart, which shall fulfil all my will.',
   'καὶ μεταστήσας αὐτὸν ἤγειρεν τὸν Δαυὶδ αὐτοῖς εἰς βασιλέα, ᾧ καὶ εἶπεν μαρτυρήσας· εὗρον Δαυὶδ τὸν τοῦ Ἰεσσαί, ἄνδρα κατὰ τὴν καρδίαν μου, ὃς ποιήσει πάντα τὰ θελήματά μου.',
   'Kai metastēsas auton ēgeiren ton David autois eis basilea, hō kai eipen martyrēsas; heuron David ton tou Iessai, andra kata tēn kardian mou, hos poiēsei panta ta thelēmata mou.',
   'The quotation combines 1 Samuel 13:14 and Psalm 89:20. "Andra kata tēn kardian mou" — not "perfect man" but "one aligned with God''s purposes." The pivot from Saul to David prefigures the pivot from first Adam to Christ.',
   'God raises up the man after his own heart to lead his people. David''s anointing is the theological prototype of Christ''s: the Lord chooses not by human qualification but by heart-alignment to his will.'),
  (23, 'Of this man''s seed hath God according to his promise raised unto Israel a Saviour, Jesus:',
   'τούτου ὁ θεὸς ἀπὸ τοῦ σπέρματος κατ’ ἐπαγγελίαν ἤγαγεν τῷ Ἰσραὴλ σωτῆρα Ἰησοῦν,',
   'Toutou ho theos apo tou spermatos kat'' epangelian ēgagen tō Israēl sōtēra Iēsoun,',
   '"Kat'' epangelian" ("according to promise") — the Davidic covenant of 2 Samuel 7 is in view. "Sōtēra" ("Savior") echoes Luke 2:11. The pivot has arrived: the whole sweep of Israel''s story funnels into Jesus.',
   'Jesus is the divinely-appointed fulfillment of the Davidic promise. The messianic vocation is not a post-factum claim but the hinge on which all previous revelation was turning.'),
  (24, 'When John had first preached before his coming the baptism of repentance to all the people of Israel.',
   'προκηρύξαντος Ἰωάννου πρὸ προσώπου τῆς εἰσόδου αὐτοῦ βάπτισμα μετανοίας παντὶ τῷ λαῷ Ἰσραήλ.',
   'Prokēryxantos Iōannou pro prosōpou tēs eisodou autou baptisma metanoias panti tō laō Israēl.',
   'Paul honors John the Baptist as Christ''s forerunner (cf. 10:37; 19:4). "Baptisma metanoias" is the Lukan formula for John''s preaching. The apostolic kerygma always contextualizes Jesus within John''s preparatory ministry.',
   'True preaching of Christ honors the forerunner. John the Baptist''s preparatory ministry remains permanently part of the gospel narrative; repentance continues to precede saving faith in the economy of grace.'),
  (25, 'And as John fulfilled his course, he said, Whom think ye that I am? I am not he. But, behold, there cometh one after me, whose shoes of his feet I am not worthy to loose.',
   'ὡς δὲ ἐπλήρου Ἰωάννης τὸν δρόμον, ἔλεγεν· τί ἐμὲ ὑπονοεῖτε εἶναι; οὐκ εἰμὶ ἐγώ, ἀλλ’ ἰδοὺ ἔρχεται μετ’ ἐμὲ οὗ οὐκ εἰμὶ ἄξιος τὸ ὑπόδημα τῶν ποδῶν λῦσαι.',
   'Hōs de eplērou Iōannēs ton dromon, elegen; ti eme hyponoeite einai? Ouk eimi egō, all'' idou erchetai met'' eme hou ouk eimi axios to hypodēma tōn podōn lysai.',
   '"Eplērou… ton dromon" ("was finishing his course") — Paul''s favorite athletic metaphor for a completed ministry (cf. 20:24; 2 Tim 4:7). John''s decisive self-effacement is recalled: the greatest forerunner is unworthy to do a slave''s task for the Coming One.',
   'Christian ministers exist to point beyond themselves to Christ. The greatness of John the Baptist is measured by the depth of his self-effacement; whoever magnifies the minister above the Master has ceased to serve the gospel.'),
  (26, 'Men and brethren, children of the stock of Abraham, and whosoever among you feareth God, to you is the word of this salvation sent.',
   'ἄνδρες ἀδελφοί, υἱοὶ γένους Ἀβραὰμ καὶ οἱ ἐν ὑμῖν φοβούμενοι τὸν θεόν, ἡμῖν ὁ λόγος τῆς σωτηρίας ταύτης ἐξαπεστάλη.',
   'Andres adelphoi, huioi genous Abraam kai hoi en hymin phoboumenoi ton theon, hēmin ho logos tēs sōtērias tautēs exapestalē.',
   'Paul restates the dual address of v.16 and stakes his claim: the "word of this salvation" is "sent to us" — Jew and Gentile together. The plural "hēmin" ("to us") deliberately binds speaker and hearers.',
   'The gospel is specifically, deliberately addressed to both Jews and Gentiles simultaneously. No racial or religious pedigree confers superiority; nor does its lack disqualify; both hear the same word of salvation.'),
  (27, 'For they that dwell at Jerusalem, and their rulers, because they knew him not, nor yet the voices of the prophets which are read every sabbath day, they have fulfilled them in condemning him.',
   'οἱ γὰρ κατοικοῦντες ἐν Ἰερουσαλὴμ καὶ οἱ ἄρχοντες αὐτῶν τοῦτον ἀγνοήσαντες καὶ τὰς φωνὰς τῶν προφητῶν τὰς κατὰ πᾶν σάββατον ἀναγινωσκομένας κρίναντες ἐπλήρωσαν,',
   'Hoi gar katoikountes en Ierousalēm kai hoi archontes autōn touton agnoēsantes kai tas phōnas tōn prophētōn tas kata pan sabbaton anaginōskomenas krinantes eplērōsan,',
   'Stunning paradox: in condemning Christ, Jerusalem''s rulers fulfilled the very prophecies they heard read every sabbath. Ignorance and prophecy combine in the sovereign irony of the cross.',
   'God''s sovereign purposes are accomplished through the very actions of those who oppose him. The rulers of Jerusalem unwittingly fulfilled Scripture even as they rejected its Christ; human rebellion cannot escape the net of divine design.'),
  (28, 'And though they found no cause of death in him, yet desired they Pilate that he should be slain.',
   'καὶ μηδεμίαν αἰτίαν θανάτου εὑρόντες ᾐτήσαντο Πιλᾶτον ἀναιρεθῆναι αὐτόν·',
   'Kai mēdemian aitian thanatou heurontes ētēsanto Pilaton anairethēnai auton;',
   'Paul notes the judicial innocence of Jesus (cf. Luke 23:4, 14, 22). The rulers had no capital cause but secured his death through Roman authority. The cross is thus declared a travesty of justice.',
   'The crucifixion was a legal travesty born of religious envy. Christianity''s foundational public event is the unjust execution of an innocent man; the cross thus confronts every human system of false justice.'),
  (29, 'And when they had fulfilled all that was written of him, they took him down from the tree, and laid him in a sepulchre.',
   'ὡς δὲ ἐτέλεσαν πάντα τὰ περὶ αὐτοῦ γεγραμμένα, καθελόντες ἀπὸ τοῦ ξύλου ἔθηκαν εἰς μνημεῖον.',
   'Hōs de etelesan panta ta peri autou gegrammena, kathelontes apo tou xylou ethēkan eis mnēmeion.',
   '"Etelesan" ("they fulfilled") is ambiguous: the hostile actors "completed" all that had been written, making them instruments of the very prophecy they resisted. "Xylou" ("tree") invokes Deuteronomy 21:23''s curse — Paul''s favorite cross-term (cf. Gal 3:13).',
   'Every detail of Jesus'' death was prophesied and fulfilled. The cross is not an interruption of Scripture but its climactic expression; even the burial fulfills Isaiah 53:9.'),
  (30, 'But God raised him from the dead:',
   'ὁ δὲ θεὸς ἤγειρεν αὐτὸν ἐκ νεκρῶν·',
   'Ho de theos ēgeiren auton ek nekrōn;',
   'The hinge clause of the sermon: "but God." Four simple Greek words encompass the entire gospel reversal. The Father''s raising vindicates everything Jesus claimed and every prophecy about him.',
   'The resurrection is God''s own sovereign reversal of the human verdict on Jesus. What men condemned, God vindicated; Christian faith stakes everything on this one divine act.'),
  (31, 'And he was seen many days of them which came up with him from Galilee to Jerusalem, who are his witnesses unto the people.',
   'ὃς ὤφθη ἐπὶ ἡμέρας πλείους τοῖς συναναβᾶσιν αὐτῷ ἀπὸ τῆς Γαλιλαίας εἰς Ἰερουσαλήμ, οἵτινες νῦν εἰσὶν μάρτυρες αὐτοῦ πρὸς τὸν λαόν.',
   'Hos ōphthē epi hēmeras pleious tois synanabasin autō apo tēs Galilaias eis Ierousalēm, hoitines nyn eisin martyres autou pros ton laon.',
   'Paul cites the Twelve (not himself) as the chief witnesses — an act of humility and strategic wisdom, since his own Damascus-road witness is less familiar to the audience. Resurrection appearances "for many days" preclude hallucination.',
   'The historical resurrection is multiply attested by qualified eyewitnesses. Christianity is not built on one man''s revelation but on a chorus of witnesses who saw, ate, and walked with the risen Lord.'),
  (32, 'And we declare unto you glad tidings, how that the promise which was made unto the fathers,',
   'καὶ ἡμεῖς ὑμᾶς εὐαγγελιζόμεθα τὴν πρὸς τοὺς πατέρας ἐπαγγελίαν γενομένην,',
   'Kai hēmeis hymas euangelizometha tēn pros tous pateras epangelian genomenēn,',
   '"Euangelizometha" ("we proclaim good news") — the verb of gospel announcement. The promise made to the fathers (patriarchs, David) is announced as fulfilled in this audience''s hearing.',
   'The gospel is fulfillment-language. Every generation that hears the gospel is the generation to whom ancient promise is newly and savingly delivered; what was sealed for the fathers is unsealed for the sons.'),
  (33, 'God hath fulfilled the same unto us their children, in that he hath raised up Jesus again; as it is also written in the second psalm, Thou art my Son, this day have I begotten thee.',
   'ὅτι ταύτην ὁ θεὸς ἐκπεπλήρωκεν τοῖς τέκνοις ἡμῶν ἀναστήσας Ἰησοῦν, ὡς καὶ ἐν τῷ ψαλμῷ γέγραπται τῷ δευτέρῳ· υἱός μου εἶ σύ, ἐγὼ σήμερον γεγέννηκά σε.',
   'Hoti tautēn ho theos ekpeplērōken tois teknois hēmōn anastēsas Iēsoun, hōs kai en tō psalmō gegraptai tō deuterō; huios mou ei sy, egō sēmeron gegennēka se.',
   'Paul quotes Psalm 2:7 and applies it to the resurrection. "Anastēsas" here likely denotes the resurrection specifically (cf. v.34 "anastēsen auton ek nekrōn"); the "begetting" is Jesus'' coronation as cosmic king by being raised from the dead (cf. Rom 1:4).',
   'The resurrection is the Son''s enthronement as Davidic king over all nations. Psalm 2''s decree is discharged in Jesus''s rising: "this day" is resurrection day, "my Son" is the risen Christ, and the nations are his inheritance.'),
  (34, 'And as concerning that he raised him up from the dead, now no more to return to corruption, he said on this wise, I will give you the sure mercies of David.',
   'ὅτι δὲ ἀνέστησεν αὐτὸν ἐκ νεκρῶν μηκέτι μέλλοντα ὑποστρέφειν εἰς διαφθοράν, οὕτως εἴρηκεν ὅτι δώσω ὑμῖν τὰ ὅσια Δαυὶδ τὰ πιστά.',
   'Hoti de anestēsen auton ek nekrōn mēketi mellonta hypostrephein eis diaphthoran, houtōs eirēken hoti dōsō hymin ta hosia David ta pista.',
   'Paul quotes Isaiah 55:3 (LXX): "holy mercies of David" or "faithful holy things of David" — the covenant promises of 2 Sam 7 that require an everlasting Davidic descendant. A corruptible (i.e. dying) Messiah cannot fulfill them; Christ''s resurrection "to no more corruption" thus fulfills Isaiah 55.',
   'The irreversibility of Christ''s resurrection is the guarantee of the everlasting Davidic covenant. Only a Son who dies no more can reign forever; thus the resurrection is the pledge of all messianic blessings.'),
  (35, 'Wherefore he saith also in another psalm, Thou shalt not suffer thine Holy One to see corruption.',
   'διότι καὶ ἐν ἑτέρῳ λέγει· οὐ δώσεις τὸν ὅσιόν σου ἰδεῖν διαφθοράν.',
   'Dioti kai en heterō legei; ou dōseis ton hosion sou idein diaphthoran.',
   'Paul quotes Psalm 16:10 (LXX), the same text Peter used at Pentecost (2:27). The argument from Psalm 16 is the cornerstone of apostolic resurrection exegesis: a Psalm David wrote cannot apply to David (who did see corruption — v.36), so it must speak of David''s greater Son.',
   'Psalm 16 is the scriptural charter of the resurrection. David''s confidence that the Holy One would not see decay could not be his own experience and must therefore be the Messiah''s; the Psalms themselves anticipate the empty tomb.'),
  (36, 'For David, after he had served his own generation by the will of God, fell on sleep, and was laid unto his fathers, and saw corruption:',
   'Δαυὶδ μὲν γὰρ ἰδίᾳ γενεᾷ ὑπηρετήσας τῇ τοῦ θεοῦ βουλῇ ἐκοιμήθη καὶ προσετέθη πρὸς τοὺς πατέρας αὐτοῦ καὶ εἶδεν διαφθοράν,',
   'David men gar idia genea hypēretēsas tē tou theou boulē ekoimēthē kai prosetethē pros tous pateras autou kai eiden diaphthoran,',
   '"Hypēretēsas tē tou theou boulē" — David "served the will of God" in his generation, then died. The eulogy is carefully framed to highlight limitation: great as David was, he saw corruption; a greater son must be in view.',
   'Each generation of believers serves God''s eternal purpose within its own finite limits. David "served his own generation by the will of God" — a noble epitaph of the Christian who contributes faithfully to a purpose larger than his own lifespan.'),
  (37, 'But he, whom God raised again, saw no corruption.',
   'ὃν δὲ ὁ θεὸς ἤγειρεν, οὐκ εἶδεν διαφθοράν.',
   'Hon de ho theos ēgeiren, ouk eiden diaphthoran.',
   'The climactic contrast in the sermon''s rhetoric. Nine words in Greek settle the argument: God raised him; corruption is impossible for such a one.',
   'The resurrection, proved from David''s own Psalter, is the watershed that divides David from Christ, corruption from incorruption, mortality from resurrection life. Everything of Christian hope turns on these nine Greek words.'),
  (38, 'Be it known unto you therefore, men and brethren, that through this man is preached unto you the forgiveness of sins:',
   'γνωστὸν οὖν ἔστω ὑμῖν, ἄνδρες ἀδελφοί, ὅτι διὰ τούτου ὑμῖν ἄφεσις ἁμαρτιῶν καταγγέλλεται,',
   'Gnōston oun estō hymin, andres adelphoi, hoti dia toutou hymin aphesis hamartiōn katangelletai,',
   'The applicatory climax: "forgiveness of sins" is the offered benefit. "Dia toutou" ("through this man") — the exclusivity of Christ''s mediation is underscored. "Katangelletai" is public, solemn proclamation.',
   'The saving benefit of Christ''s resurrection is the forgiveness of sins, offered through his person alone. No competing mediator, no supplementary human effort, no Jewish ceremonial achievement supplements the sufficiency of Jesus.'),
  (39, 'And by him all that believe are justified from all things, from which ye could not be justified by the law of Moses.',
   'καὶ ἀπὸ πάντων ὧν οὐκ ἠδυνήθητε ἐν νόμῳ Μωϋσέως δικαιωθῆναι, ἐν τούτῳ πᾶς ὁ πιστεύων δικαιοῦται.',
   'Kai apo pantōn hōn ouk ēdynēthēte en nomō Mōuseōs dikaiōthēnai, en toutō pas ho pisteuōn dikaioutai.',
   'The Pauline doctrine of justification by faith is here publicly stated for the first time in Acts. "Pas ho pisteuōn" ("everyone who believes") — universal scope. "En toutō… dikaioutai" ("is justified in him") — ground of justification is the risen Christ, not the Mosaic law.',
   'Justification is the free declaration that the believer is righteous before God, grounded in Christ''s death and resurrection and received through faith alone. The Mosaic law exposed sin but could not remove guilt; the gospel both exposes and forgives — this is the heart of Paul''s gospel.'),
  (40, 'Beware therefore, lest that come upon you, which is spoken of in the prophets;',
   'βλέπετε οὖν μὴ ἐπέλθῃ τὸ εἰρημένον ἐν τοῖς προφήταις·',
   'Blepete oun mē epelthē to eirēmenon en tois prophētais;',
   'Paul''s sermon climaxes with warning — not flattery. The good news is accompanied by a serious caution: those who reject fulfilled promise risk fulfilled judgment.',
   'Biblical preaching holds together grace offered and judgment warned. The gospel is not a unilateral gift but an address that demands response; those who turn from salvation fall under the prophesied wrath.'),
  (41, 'Behold, ye despisers, and wonder, and perish: for I work a work in your days, a work which ye shall in no wise believe, though a man declare it unto you.',
   'ἴδετε, οἱ καταφρονηταί, καὶ θαυμάσατε καὶ ἀφανίσθητε, ὅτι ἔργον ἐργάζομαι ἐγὼ ἐν ταῖς ἡμέραις ὑμῶν, ἔργον ὃ οὐ μὴ πιστεύσητε ἐάν τις ἐκδιηγῆται ὑμῖν.',
   'Idete, hoi kataphronētai, kai thaumasate kai aphanisthēte, hoti ergon ergazomai egō en tais hēmerais hymōn, ergon ho ou mē pisteusēte ean tis ekdiēgētai hymin.',
   'Paul quotes Habakkuk 1:5 (LXX). Habakkuk warned of the Babylonian invasion as God''s unbelievable work; Paul applies it to the cross-resurrection-Gentile mission complex — an equally unbelievable divine work now being accomplished. Rejection parallels Judah''s rejection before the exile.',
   'History''s most astonishing divine works are often those that his own people refuse to believe. The gospel is hardest to accept precisely because its scope and method exceed what religious imagination expects; unbelief invites the same judgment Habakkuk''s generation incurred.'),
  (42, 'And when the Jews were gone out of the synagogue, the Gentiles besought that these words might be preached to them the next sabbath.',
   'Ἐξιόντων δὲ αὐτῶν παρεκάλουν εἰς τὸ μεταξὺ σάββατον λαληθῆναι αὐτοῖς τὰ ῥήματα ταῦτα.',
   'Exiontōn de autōn parekaloun eis to metaxy sabbaton lalēthēnai autois ta rhēmata tauta.',
   'The critical texts do not have "Jews" and "Gentiles"; they simply say "as they went out, they urged." Either way, an invitation is extended for a second sabbath hearing — the gospel has taken root.',
   'Genuine gospel hearers hunger for more. The test of a good sermon is whether hearers beg to hear it again; Paul''s Christ-centered biblical preaching produced exactly that response.'),
  (43, 'Now when the congregation was broken up, many of the Jews and religious proselytes followed Paul and Barnabas: who, speaking to them, persuaded them to continue in the grace of God.',
   'λυθείσης δὲ τῆς συναγωγῆς ἠκολούθησαν πολλοὶ τῶν Ἰουδαίων καὶ τῶν σεβομένων προσηλύτων τῷ Παύλῳ καὶ τῷ Βαρναβᾷ, οἵτινες προσλαλοῦντες αὐτοῖς ἔπειθον αὐτοὺς προσμένειν τῇ χάριτι τοῦ θεοῦ.',
   'Lytheisēs de tēs synagōgēs ēkolouthēsan polloi tōn Ioudaiōn kai tōn sebomenōn prosēlytōn tō Paulō kai tō Barnaba, hoitines proslalountes autois epeithon autous prosmenein tē chariti tou theou.',
   '"Sebomenōn prosēlytōn" ("devout proselytes," lit. God-fearers and proselytes) includes both full converts to Judaism and Gentile God-fearers. "Prosmenein tē chariti" ("to continue in grace") — perseverance, not initial belief, is the exhortation; the gospel is already received.',
   'New believers require repeated exhortation to continue in grace. Conversion is the door; perseverance is the path; gospel ministers both invite and exhort, leading the newborn to abide in the grace that first saved them.'),
  (44, 'And the next sabbath day came almost the whole city together to hear the word of God.',
   'Τῷ δὲ ἐρχομένῳ σαββάτῳ σχεδὸν πᾶσα ἡ πόλις συνήχθη ἀκοῦσαι τὸν λόγον τοῦ κυρίου.',
   'Tō de erchomenō sabbatō schedon pasa hē polis synēchthē akousai ton logon tou kyriou.',
   '"Schedon pasa hē polis" — virtually the entire city gathered. The sermon has spread by word-of-mouth during the week; the synagogue cannot contain the crowd. This is the first recorded instance of mass Gentile interest in Paul''s ministry.',
   'When the gospel is faithfully preached, whole communities are drawn to it. Public hunger for the word of God remains a pattern wherever the message of Christ is clearly declared; Gentile response often outruns Jewish response in new territory.'),
  (45, 'But when the Jews saw the multitudes, they were filled with envy, and spake against those things which were spoken by Paul, contradicting and blaspheming.',
   'ἰδόντες δὲ οἱ Ἰουδαῖοι τοὺς ὄχλους ἐπλήσθησαν ζήλου καὶ ἀντέλεγον τοῖς ὑπὸ Παύλου λαλουμένοις ἀντιλέγοντες καὶ βλασφημοῦντες.',
   'Idontes de hoi Ioudaioi tous ochlous eplēsthēsan zēlou kai antelegon tois hypo Paulou laloumenois antilegontes kai blasphēmountes.',
   '"Zēlos" ("envy, jealousy") — the same emotion that delivered Jesus to Pilate (Matt 27:18) and arrested the apostles (5:17). Ethnic protectionism eclipses theological discernment when the Gentiles appear about to claim the covenant.',
   'Envy is the characteristic sin of those whose religious identity is threatened by genuine grace among others. When gospel blessing falls outside expected boundaries, insiders are often tempted to oppose rather than rejoice; the history of the church has repeatedly borne this sad pattern.'),
  (46, 'Then Paul and Barnabas waxed bold, and said, It was necessary that the word of God should first have been spoken to you: but seeing ye put it from you, and judge yourselves unworthy of everlasting life, lo, we turn to the Gentiles.',
   'παρρησιασάμενοί τε ὁ Παῦλος καὶ ὁ Βαρναβᾶς εἶπαν· ὑμῖν ἦν ἀναγκαῖον πρῶτον λαληθῆναι τὸν λόγον τοῦ θεοῦ· ἐπειδὴ ἀπωθεῖσθε αὐτὸν καὶ οὐκ ἀξίους κρίνετε ἑαυτοὺς τῆς αἰωνίου ζωῆς, ἰδοὺ στρεφόμεθα εἰς τὰ ἔθνη.',
   'Parrēsiasamenoi te ho Paulos kai ho Barnabas eipan; hymin ēn anankaion prōton lalēthēnai ton logon tou theou; epeidē apōtheisthe auton kai ouk axious krinete heautous tēs aiōniou zōēs, idou strephometha eis ta ethnē.',
   '"Anankaion prōton" ("necessary first") honors the Jewish priority (Rom 1:16). "Ouk axious krinete heautous" ("you judge yourselves unworthy") — their own rejection passes the verdict on themselves. "Strephometha eis ta ethnē" is a solemn declaration, not a permanent policy; Paul will continue entering synagogues first city by city.',
   'Rejection of the gospel is self-condemnation. God neither abandons nor overrides the rejector; he withdraws the offered gift and extends it to those who will receive, with the door remaining open to the rejector''s future repentance.'),
  (47, 'For so hath the Lord commanded us, saying, I have set thee to be a light of the Gentiles, that thou shouldest be for salvation unto the ends of the earth.',
   'οὕτως γὰρ ἐντέταλται ἡμῖν ὁ κύριος· τέθεικά σε εἰς φῶς ἐθνῶν τοῦ εἶναί σε εἰς σωτηρίαν ἕως ἐσχάτου τῆς γῆς.',
   'Houtōs gar entetaltai hēmin ho kyrios; tetheika se eis phōs ethnōn tou einai se eis sōtērian heōs eschatou tēs gēs.',
   'Paul quotes Isaiah 49:6 — originally addressed to the Servant of the Lord (ultimately Christ), now applied corporately to the church''s Gentile mission. Paul identifies himself as an extension of the Servant''s light-bearing vocation. "Heōs eschatou tēs gēs" echoes Acts 1:8.',
   'The church''s Gentile mission is the direct extension of Christ''s own servant vocation. Paul does not invent a mission; he inherits the Messiah''s own calling, shining the light of Christ "to the ends of the earth."'),
  (48, 'And when the Gentiles heard this, they were glad, and glorified the word of the Lord: and as many as were ordained to eternal life believed.',
   'ἀκούοντα δὲ τὰ ἔθνη ἔχαιρον καὶ ἐδόξαζον τὸν λόγον τοῦ κυρίου, καὶ ἐπίστευσαν ὅσοι ἦσαν τεταγμένοι εἰς ζωὴν αἰώνιον·',
   'Akouonta de ta ethnē echairon kai edoxazon ton logon tou kyriou, kai episteusan hosoi ēsan tetagmenoi eis zōēn aiōnion;',
   '"Hosoi ēsan tetagmenoi eis zōēn aiōnion" ("as many as were appointed/ordained to eternal life") — one of the NT''s clearest statements of divine election preceding human faith. The perfect participle "tetagmenoi" describes a prior decisive act of God.',
   'Election unto eternal life precedes and grounds human faith. God''s sovereign appointment is the decisive cause of believing; human response flows from divine ordination, not the reverse. The doctrine is asserted without defense, as a simple fact of the gospel''s reception.'),
  (49, 'And the word of the Lord was published throughout all the region.',
   'διεφέρετο δὲ ὁ λόγος τοῦ κυρίου δι’ ὅλης τῆς χώρας.',
   'Diephereto de ho logos tou kyriou di'' holēs tēs chōras.',
   'Pisidian Antioch becomes a regional hub: new converts carry the gospel to surrounding villages and cities. Galatians 1:2 ("churches of Galatia" plural) may reflect this broader diffusion.',
   'Apostolic evangelism rapidly multiplies into indigenous regional witness. A single preaching center becomes a network; the gospel''s propagation is viral, carried by ordinary converts into every neighboring settlement.'),
  (50, 'But the Jews stirred up the devout and honourable women, and the chief men of the city, and raised persecution against Paul and Barnabas, and expelled them out of their coasts.',
   'οἱ δὲ Ἰουδαῖοι παρώτρυναν τὰς σεβομένας γυναῖκας τὰς εὐσχήμονας καὶ τοὺς πρώτους τῆς πόλεως καὶ ἐπήγειραν διωγμὸν ἐπὶ τὸν Παῦλον καὶ Βαρναβᾶν καὶ ἐξέβαλον αὐτοὺς ἀπὸ τῶν ὁρίων αὐτῶν.',
   'Hoi de Ioudaioi parōtrynan tas sebomenas gynaikas tas euschēmonas kai tous prōtous tēs poleōs kai epēgeiran diōgmon epi ton Paulon kai Barnaban kai exebalon autous apo tōn horiōn autōn.',
   '"Tas sebomenas gynaikas tas euschēmonas" ("devout and prominent women") — influential God-fearing women with status in Roman colonial society, recruited to pressure "the chief men of the city" (the decurions). The synagogue uses civic and social networks to mobilize Roman authority against the missionaries.',
   'Religious opposition to the gospel often enlists civic and social power. The combination of public influence with religious fervor has historically been the most effective weapon against Christian witness, from Pisidian Antioch to every later century.'),
  (51, 'But they shook off the dust of their feet against them, and came unto Iconium.',
   'οἱ δὲ ἐκτιναξάμενοι τὸν κονιορτὸν τῶν ποδῶν ἐπ’ αὐτοὺς ἦλθον εἰς Ἰκόνιον,',
   'Hoi de ektinaxamenoi ton koniorton tōn podōn ep'' autous ēlthon eis Ikonion,',
   'Shaking off dust is Jesus'' directive for towns that reject the message (Matt 10:14; Mark 6:11; Luke 9:5). It signifies formal testimony against the city''s rejection and freedom from responsibility for its fate. Iconium (modern Konya) is about 90 miles east, still in the Roman province of Galatia.',
   'Christian missionaries do not linger where the gospel has been decisively rejected. Shaking off dust formalizes the transfer of responsibility: the messengers have discharged their duty and proceed; the rejectors now answer to God alone.'),
  (52, 'And the disciples were filled with joy, and with the Holy Ghost.',
   'οἵ τε μαθηταὶ ἐπληροῦντο χαρᾶς καὶ πνεύματος ἁγίου.',
   'Hoi te mathētai eplērounto charas kai pneumatos hagiou.',
   'Luke closes the chapter with unexpected accent: the new Pisidian converts, though their missionaries have been expelled, are filled — imperfect tense, continual filling — with joy and Spirit. Persecution has not cost them the gospel but confirmed them in it.',
   'Authentic gospel fellowship, though stripped of founding leaders, continues to be supplied by the Spirit himself. Joy and fullness are marks of a church that has received Christ, not simply a church with a preacher; the Spirit is the abiding pastor of every persecuted congregation.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 13
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

-- 3. Word studies
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'προφῆται καὶ διδάσκαλοι', 'prophētai kai didaskaloi', 'G4396/G1320', 'Prophets and teachers. Two distinguished offices of the early church, often overlapping in practice.', 1),
  (1, 'σύντροφος', 'syntrophos', 'G4939', 'Foster-brother, raised together. Manaen shared Herod Antipas''s upbringing.', 2),
  (2, 'λειτουργούντων', 'leitourgountōn', 'G3008', 'Ministering, performing priestly service. Root of ''liturgy.''', 3),
  (2, 'ἀφορίσατε', 'aphorisate', 'G873', 'Set apart, separate. The same verb Paul uses of himself (Rom 1:1; Gal 1:15).', 4),
  (3, 'ἐπιθέντες τὰς χεῖρας', 'epithentes tas cheiras', 'G2007/G5495', 'Laying on of hands. Communal commissioning ritual, signifying identification and delegation.', 5),
  (6, 'μάγον', 'magon', 'G3097', 'Magician, sorcerer. Same word as the Magi in Matthew 2; condemnatory context here.', 6),
  (6, 'ψευδοπροφήτην', 'pseudoprophētēn', 'G5578', 'False prophet. Bar-Jesus is condemned both as sorcerer and false spokesman.', 7),
  (7, 'ἀνθυπάτῳ', 'anthypatō', 'G446', 'Proconsul. Precisely correct Roman title for senatorial provinces; historical accuracy verified archeologically.', 8),
  (7, 'συνετῷ', 'synetō', 'G4908', 'Prudent, intelligent, discerning. Sergius Paulus''s thoughtful disposition is noted favorably.', 9),
  (9, 'Παῦλος', 'Paulos', 'G3972', 'Paul. First Lukan use of the apostle''s Roman name; henceforth his standard designation.', 10),
  (10, 'δόλου', 'dolou', 'G1388', 'Guile, deceit, treachery. Characterizes Elymas''s spiritual methodology.', 11),
  (10, 'υἱὲ διαβόλου', 'huie diabolou', 'G5207/G1228', 'Son of the devil. Pointed pun on Bar-Jesus (son of Jesus).', 12),
  (10, 'διαστρέφων', 'diastrephōn', 'G1294', 'Perverting, twisting crooked. Describes satanic distortion of divine paths.', 13),
  (11, 'ἀχλὺς', 'achlys', 'G887', 'Mist, dim haze. Medical term for clouded vision; Luke''s physician''s eye.', 14),
  (15, 'λόγος παρακλήσεως', 'logos paraklēseōs', 'G3056/G3874', 'Word of exhortation. Technical term for synagogue homily (Heb 13:22).', 15),
  (16, 'ἀκούσατε', 'akousate', 'G191', 'Listen, hear. Aorist imperative; formal summons to attentive hearing.', 16),
  (18, 'ἐτροποφόρησεν', 'etropophorēsen', 'G5159', 'Bore with, endured the manners of. Rare verb of divine forbearance toward sin.', 17),
  (22, 'κατὰ τὴν καρδίαν μου', 'kata tēn kardian mou', 'G2596/G2588', 'According to my heart. Alignment with God''s purposes, not moral perfection.', 18),
  (23, 'σπέρματος', 'spermatos', 'G4690', 'Seed, offspring. Davidic covenant language; Jesus as David''s seed.', 19),
  (23, 'ἐπαγγελίαν', 'epangelian', 'G1860', 'Promise. The Davidic and Abrahamic promises converge in Christ.', 20),
  (29, 'ξύλου', 'xylou', 'G3586', 'Tree, wood. Pauline cross-term evoking Deut 21:23 curse.', 21),
  (30, 'ἤγειρεν', 'ēgeiren', 'G1453', 'Raised up. Divine act of resurrection; hinge verb of the sermon.', 22),
  (31, 'ὤφθη', 'ōphthē', 'G3700', 'Was seen, appeared. Standard resurrection-appearance verb.', 23),
  (33, 'γεγέννηκά', 'gegennēka', 'G1080', 'I have begotten. Perfect tense; coronation language from Psalm 2:7.', 24),
  (34, 'διαφθοράν', 'diaphthoran', 'G1312', 'Corruption, decay. Bodily decomposition; what Christ''s body did not experience.', 25),
  (34, 'ὅσια', 'hosia', 'G3741', 'Holy things, faithful mercies. From Isaiah 55:3 LXX—the Davidic covenant mercies.', 26),
  (36, 'βουλῇ', 'boulē', 'G1012', 'Will, counsel, purpose. God''s determinate plan; David served it generationally.', 27),
  (38, 'ἄφεσις', 'aphesis', 'G859', 'Forgiveness, release. Core apostolic offer; release from the debt of sin.', 28),
  (38, 'καταγγέλλεται', 'katangelletai', 'G2605', 'Is proclaimed publicly. Solemn announcement verb; more formal than euangelizō.', 29),
  (39, 'δικαιοῦται', 'dikaioutai', 'G1344', 'Is justified, declared righteous. Forensic verb; the heart of Pauline soteriology.', 30),
  (39, 'πιστεύων', 'pisteuōn', 'G4100', 'Believing. Present participle; ongoing trust as the instrument of justification.', 31),
  (45, 'ζήλου', 'zēlou', 'G2205', 'Envy, jealous rivalry. Same noun that delivered Jesus to the cross (Matt 27:18).', 32),
  (46, 'παρρησιασάμενοι', 'parrēsiasamenoi', 'G3955', 'Speaking boldly. Hallmark virtue of Acts preaching.', 33),
  (46, 'στρεφόμεθα', 'strephometha', 'G4762', 'We turn. Formal declaration of mission-pivot; locally decisive, globally ongoing.', 34),
  (47, 'φῶς ἐθνῶν', 'phōs ethnōn', 'G5457/G1484', 'Light of the Gentiles. Isaianic title of the Servant (Isa 49:6), now applied to apostolic mission.', 35),
  (48, 'τεταγμένοι', 'tetagmenoi', 'G5021', 'Appointed, ordained, arranged. Perfect passive participle—divine election preceding belief.', 36),
  (52, 'ἐπληροῦντο', 'eplērounto', 'G4137', 'Were being filled. Imperfect passive; continuous, repeated filling of the Spirit.', 37)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 13 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

